let unitPrice = "{{unitPrice}}"
let subtotal = "{{subtotalRenew}}";
let discount = "{{discountRenew}}"

if (discount === ""){
    discount = "0.00";
};

let tax = "{{taxRenew}}";
if (tax === ""){
    tax = "0.00";
};
let total = "{{totalRenew}}";

subtotal = subtotal.replace(",","").trim();
unitPrice = unitPrice.replace(",","").trim();
discount = discount.replace(",","").trim();
tax = tax.replace(",","").trim();
total = total.replace(",","").trim();

unitPrice = Number(unitPrice.replace("{{Symbol}}",""));
discount = Number(discount.replace("{{Symbol}}",""));
subtotal = Number(subtotal.replace("{{Symbol}}",""));
tax = Number(tax.replace("{{Symbol}}",""));
total = Number(total.replace("{{Symbol}}",""));


let total2 = unitPrice-discount+tax;
total2 = Number(total2.toFixed(2));

return total === total2 && subtotal === unitPrice
